export type Recipe = {
  id: string;
  name: string;
  emoji: string;
  category: RecipeCategory;
  tags: RecipeTag[];
  minutes: number;
  servings: number;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
  ingredients: string[];
  steps: string[];
  /** Oven/pan temperature in °C, when relevant. */
  tempC?: number;
};

